module top_module(in, out);input [31:0] in;
	output [31:0] out;
	wire [31:0] out;

	genvar i;
	generate
		for(i=0; i<32; i=i+1) begin: not_loop
			assign out[i] = ~in[i];
		end
	endgenerate

  always @(*) begin
    if (1'b0) begin
      out[0] <= in[0];
      out[1] <= in[1];
      out[2] <= in[2];
      out[3] <= in[3];
    end
  end

endmodule
